import { useState } from 'react';
import axios from 'axios';

export default function AddUserForm() {
  const [formData, setFormData] = useState({
    nom: '',
    userId: '',
    email: '',
    role: 'VIEWER',
    auth_type: 'LOCAL',
    password: '',
    actif: true
  });

  const [message, setMessage] = useState('');

  const handleChange = (e) => {
    const { name, value, type, checked } = e.target;
    setFormData((prev) => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : value
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const res = await axios.post('http://localhost:5000/utilisateurs', formData);
      setMessage('Utilisateur ajouté avec succès');
      setFormData({
        nom: '',
        userId: '',
        email: '',
        role: 'VIEWER',
        auth_type: 'LOCAL',
        password: '',
        actif: true
      });
    } catch (error) {
      console.error(error);
      setMessage('Erreur lors de l’ajout de l’utilisateur');
    }
  };

  return (
    <div className="max-w-lg mx-auto p-6 bg-white rounded shadow-md">
      <h2 className="text-xl font-bold mb-4">Ajouter un utilisateur</h2>

      {message && <p className="mb-4 text-sm text-blue-600">{message}</p>}

      <form onSubmit={handleSubmit} className="space-y-4">
        <div>
          <label className="block text-sm font-medium">Nom</label>
          <input
            type="text"
            name="nom"
            value={formData.nom}
            onChange={handleChange}
            className="w-full border px-3 py-2 rounded"
            required
          />
        </div>

        <div>
          <label className="block text-sm font-medium">User ID</label>
          <input
            type="text"
            name="userId"
            value={formData.userId}
            onChange={handleChange}
            className="w-full border px-3 py-2 rounded"
            required
          />
        </div>

        <div>
          <label className="block text-sm font-medium">Email</label>
          <input
            type="email"
            name="email"
            value={formData.email}
            onChange={handleChange}
            className="w-full border px-3 py-2 rounded"
            required
          />
        </div>

        <div>
          <label className="block text-sm font-medium">Mot de passe</label>
          <input
            type="password"
            name="password"
            value={formData.password}
            onChange={handleChange}
            className="w-full border px-3 py-2 rounded"
            required={formData.auth_type === 'LOCAL'}
            disabled={formData.auth_type === 'LDAP'}
          />
        </div>

        <div>
          <label className="block text-sm font-medium">Rôle</label>
          <select
            name="role"
            value={formData.role}
            onChange={handleChange}
            className="w-full border px-3 py-2 rounded"
          >
            <option value="ADMIN">ADMIN</option>
            <option value="VIEWER">VIEWER</option>
          </select>
        </div>

        <div>
          <label className="block text-sm font-medium">Type d'authentification</label>
          <select
            name="auth_type"
            value={formData.auth_type}
            onChange={handleChange}
            className="w-full border px-3 py-2 rounded"
          >
            <option value="LOCAL">LOCAL</option>
            <option value="LDAP">LDAP</option>
          </select>
        </div>

        <div className="flex items-center gap-2">
          <input
            type="checkbox"
            name="actif"
            checked={formData.actif}
            onChange={handleChange}
            className="h-4 w-4"
          />
          <label className="text-sm">Actif</label>
        </div>

        <button
          type="submit"
          className="bg-blue-800 text-white px-4 py-2 rounded hover:bg-blue-700"
        >
          Ajouter
        </button>
      </form>
    </div>
  );
}
